@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">@(editingShipment.Id == 0 ? "Create" : "Edit") Shipment</h5>
            <EditForm Model="editingShipment" OnValidSubmit="SaveShipment" FormName="shipmentForm">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Destination" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="editingShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Description" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editingShipment.Status">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="editingShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-12">
                        <button type="submit" class="btn btn-success me-2">Save</button>
                        <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found. Create one to get started.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => EditShipment(shipment)">Edit</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private Shipment editingShipment = new();
    private bool showForm;
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        editingShipment = new Shipment { EstimatedDelivery = DateTime.Today.AddDays(5) };
        showForm = true;
    }

    private void EditShipment(Shipment shipment)
    {
        editingShipment = new Shipment
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description,
            CreatedAt = shipment.CreatedAt
        };
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editingShipment.Id == 0)
        {
            var created = await ShipmentService.CreateShipmentAsync(editingShipment);
            shipments?.Add(created);
        }
        else
        {
            var updated = await ShipmentService.UpdateShipmentAsync(editingShipment);
            var index = shipments?.FindIndex(s => s.Id == updated.Id) ?? -1;
            if (index >= 0) shipments![index] = updated;
        }
        showForm = false;
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment == null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
    </div>
}

@if (shipment != null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
