@code {
    private List<Shipment>? shipments;
    private Shipment editingShipment = new();
    private bool showForm;
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        editingShipment = new Shipment { EstimatedDelivery = DateTime.Today.AddDays(5) };
        showForm = true;
    }

    private void EditShipment(Shipment shipment)
    {
        editingShipment = new Shipment
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description,
            CreatedAt = shipment.CreatedAt
        };
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editingShipment.Id == 0)
        {
            var created = await ShipmentService.CreateShipmentAsync(editingShipment);
            shipments?.Add(created);
        }
        else
        {
            var updated = await ShipmentService.UpdateShipmentAsync(editingShipment);
            var index = shipments?.FindIndex(s => s.Id == updated.Id) ?? -1;
            if (index >= 0) shipments![index] = updated;
        }
        showForm = false;
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

